import{_ as e,c as i,o as a,d as n}from"./app.05a75977.js";const g=JSON.parse('{"title":"Chapter 1: What is Machine Learning (Beyond Buzzwords)","description":"","frontmatter":{},"headers":[{"level":2,"title":"1.1 The Shift from Programming to Learning","slug":"_1-1-the-shift-from-programming-to-learning","link":"#_1-1-the-shift-from-programming-to-learning","children":[]},{"level":2,"title":"1.2 The Core Idea of Machine Learning","slug":"_1-2-the-core-idea-of-machine-learning","link":"#_1-2-the-core-idea-of-machine-learning","children":[]},{"level":2,"title":"1.3 A Simple Everyday Example","slug":"_1-3-a-simple-everyday-example","link":"#_1-3-a-simple-everyday-example","children":[]},{"level":2,"title":"1.4 Breaking Down the ML System","slug":"_1-4-breaking-down-the-ml-system","link":"#_1-4-breaking-down-the-ml-system","children":[{"level":3,"title":"1. Data","slug":"_1-data","link":"#_1-data","children":[]},{"level":3,"title":"2. Features","slug":"_2-features","link":"#_2-features","children":[]},{"level":3,"title":"3. Model","slug":"_3-model","link":"#_3-model","children":[]},{"level":3,"title":"4. Prediction","slug":"_4-prediction","link":"#_4-prediction","children":[]}]},{"level":2,"title":"1.5 Training vs Using the Model","slug":"_1-5-training-vs-using-the-model","link":"#_1-5-training-vs-using-the-model","children":[{"level":3,"title":"Training Phase","slug":"training-phase","link":"#training-phase","children":[]},{"level":3,"title":"Inference (Prediction) Phase","slug":"inference-prediction-phase","link":"#inference-prediction-phase","children":[]}]},{"level":2,"title":"1.6 Why Machine Learning Matters","slug":"_1-6-why-machine-learning-matters","link":"#_1-6-why-machine-learning-matters","children":[]},{"level":2,"title":"1.7 When to Use Machine Learning","slug":"_1-7-when-to-use-machine-learning","link":"#_1-7-when-to-use-machine-learning","children":[]},{"level":2,"title":"1.8 Common Misunderstanding","slug":"_1-8-common-misunderstanding","link":"#_1-8-common-misunderstanding","children":[]},{"level":2,"title":"1.9 A Clear Mental Model","slug":"_1-9-a-clear-mental-model","link":"#_1-9-a-clear-mental-model","children":[]},{"level":2,"title":"1.10 What Comes Next","slug":"_1-10-what-comes-next","link":"#_1-10-what-comes-next","children":[]},{"level":2,"title":"Chapter Summary","slug":"chapter-summary","link":"#chapter-summary","children":[]}],"relativePath":"ml-foundation/en/part1/what-is-machine-learning.md"}'),t={name:"ml-foundation/en/part1/what-is-machine-learning.md"},r=n('<h1 id="chapter-1-what-is-machine-learning-beyond-buzzwords" tabindex="-1">Chapter 1: What is Machine Learning (Beyond Buzzwords) <a class="header-anchor" href="#chapter-1-what-is-machine-learning-beyond-buzzwords" aria-hidden="true">#</a></h1><hr><h2 id="_1-1-the-shift-from-programming-to-learning" tabindex="-1">1.1 The Shift from Programming to Learning <a class="header-anchor" href="#_1-1-the-shift-from-programming-to-learning" aria-hidden="true">#</a></h2><p>For decades, computers have followed a simple rule:</p><blockquote><p><strong>You tell the computer exactly what to do, and it does it.</strong></p></blockquote><p>This is called <strong>traditional programming</strong>.</p><p>If you wanted to build a spam filter earlier, you would write rules like:</p><ul><li>If an email contains the phrase \u201Cwin money\u201D \u2192 mark as spam</li><li>If the sender is unknown \u2192 mark as spam</li></ul><p>This approach works\u2026 but only to a point.</p><p>Now think about the real world. Spam emails keep changing. New words appear. Patterns evolve. Writing rules for every possible case quickly becomes impossible.</p><p>This is where a new idea emerges:</p><blockquote><p><strong>What if instead of writing rules, we let the computer learn those rules from data?</strong></p></blockquote><p>That idea is <strong>Machine Learning</strong>.</p><hr><h2 id="_1-2-the-core-idea-of-machine-learning" tabindex="-1">1.2 The Core Idea of Machine Learning <a class="header-anchor" href="#_1-2-the-core-idea-of-machine-learning" aria-hidden="true">#</a></h2><p>At its heart, Machine Learning (ML) is surprisingly simple:</p><blockquote><p><strong>Machine Learning is the process of teaching computers to learn patterns from data and make decisions based on those patterns.</strong></p></blockquote><p>Instead of explicitly programming every rule, we:</p><ol><li>Give the system <strong>data</strong></li><li>Let it <strong>learn patterns</strong></li><li>Use those patterns to make <strong>predictions</strong></li></ol><hr><h2 id="_1-3-a-simple-everyday-example" tabindex="-1">1.3 A Simple Everyday Example <a class="header-anchor" href="#_1-3-a-simple-everyday-example" aria-hidden="true">#</a></h2><p>Imagine teaching a child to recognize a dog.</p><p>You don\u2019t give the child a rulebook like:</p><ul><li>A dog has exactly this ear shape</li><li>Exactly this tail length</li></ul><p>Instead, you:</p><ul><li>Show many examples of dogs</li><li>The child observes patterns</li><li>Over time, the child can identify a dog\u2014even if it looks different</li></ul><p>Machine Learning works in a very similar way.</p><ul><li>The <strong>data</strong> is like the examples shown to the child</li><li>The <strong>model</strong> is like the child\u2019s brain</li><li>The <strong>learning process</strong> is how patterns are formed</li></ul><hr><h2 id="_1-4-breaking-down-the-ml-system" tabindex="-1">1.4 Breaking Down the ML System <a class="header-anchor" href="#_1-4-breaking-down-the-ml-system" aria-hidden="true">#</a></h2><p>Every Machine Learning system, no matter how complex, is built on four basic components:</p><h3 id="_1-data" tabindex="-1">1. Data <a class="header-anchor" href="#_1-data" aria-hidden="true">#</a></h3><p>This is the raw information.</p><p>Examples:</p><ul><li>Emails (spam or not spam)</li><li>House prices</li><li>Images</li><li>Text</li></ul><hr><h3 id="_2-features" tabindex="-1">2. Features <a class="header-anchor" href="#_2-features" aria-hidden="true">#</a></h3><p>Features are the <strong>important pieces of data</strong> that help the model learn.</p><p>For example, in email classification:</p><ul><li>Presence of certain words</li><li>Length of the email</li><li>Sender information</li></ul><p>Think of features as the <strong>clues</strong> the model uses.</p><hr><h3 id="_3-model" tabindex="-1">3. Model <a class="header-anchor" href="#_3-model" aria-hidden="true">#</a></h3><p>The model is the system that:</p><ul><li>Looks at the data</li><li>Learns patterns</li><li>Makes predictions</li></ul><p>It is not \u201Cintelligent\u201D by itself\u2014it becomes useful only after learning from data.</p><hr><h3 id="_4-prediction" tabindex="-1">4. Prediction <a class="header-anchor" href="#_4-prediction" aria-hidden="true">#</a></h3><p>After learning, the model can:</p><ul><li>Classify emails as spam or not spam</li><li>Predict house prices</li><li>Recommend products</li></ul><p>This is the final output.</p><hr><h2 id="_1-5-training-vs-using-the-model" tabindex="-1">1.5 Training vs Using the Model <a class="header-anchor" href="#_1-5-training-vs-using-the-model" aria-hidden="true">#</a></h2><p>Machine Learning has two main phases:</p><h3 id="training-phase" tabindex="-1">Training Phase <a class="header-anchor" href="#training-phase" aria-hidden="true">#</a></h3><ul><li>The model is shown data</li><li>It learns patterns</li><li>It improves over time</li></ul><p>This is where \u201Clearning\u201D happens.</p><hr><h3 id="inference-prediction-phase" tabindex="-1">Inference (Prediction) Phase <a class="header-anchor" href="#inference-prediction-phase" aria-hidden="true">#</a></h3><ul><li>The trained model is used on new data</li><li>It makes predictions</li></ul><p>For example:</p><ul><li>Training: Learning from 10,000 emails</li><li>Inference: Classifying a new email</li></ul><hr><h2 id="_1-6-why-machine-learning-matters" tabindex="-1">1.6 Why Machine Learning Matters <a class="header-anchor" href="#_1-6-why-machine-learning-matters" aria-hidden="true">#</a></h2><p>Machine Learning is not just a technical concept\u2014it powers many systems you use daily:</p><ul><li>Search engines ranking results</li><li>Recommendation systems suggesting videos or products</li><li>Fraud detection in banking</li><li>Voice assistants understanding speech</li></ul><p>These problems share one thing in common:</p><blockquote><p><strong>They are too complex to solve with fixed rules.</strong></p></blockquote><p>ML handles complexity by learning patterns from large amounts of data.</p><hr><h2 id="_1-7-when-to-use-machine-learning" tabindex="-1">1.7 When to Use Machine Learning <a class="header-anchor" href="#_1-7-when-to-use-machine-learning" aria-hidden="true">#</a></h2><p>Not every problem needs Machine Learning.</p><p>Use ML when:</p><ul><li>Rules are too complex to define manually</li><li>Data is available</li><li>Patterns exist but are not obvious</li></ul><p>Avoid ML when:</p><ul><li>A simple rule-based system works well</li><li>There is very little data</li><li>The problem requires strict logical guarantees</li></ul><hr><h2 id="_1-8-common-misunderstanding" tabindex="-1">1.8 Common Misunderstanding <a class="header-anchor" href="#_1-8-common-misunderstanding" aria-hidden="true">#</a></h2><p>Many beginners think:</p><blockquote><p>\u201CMachine Learning means the computer becomes intelligent.\u201D</p></blockquote><p>This is not accurate.</p><p>A machine learning model:</p><ul><li>Does not \u201Cunderstand\u201D like humans</li><li>Does not \u201Cthink\u201D</li><li>Does not have awareness</li></ul><p>It simply:</p><blockquote><p><strong>Finds patterns in numbers and uses them to make predictions.</strong></p></blockquote><hr><h2 id="_1-9-a-clear-mental-model" tabindex="-1">1.9 A Clear Mental Model <a class="header-anchor" href="#_1-9-a-clear-mental-model" aria-hidden="true">#</a></h2><p>If you remember only one idea from this chapter, remember this:</p><blockquote><p><strong>Machine Learning = Learning patterns from data \u2192 using those patterns to make predictions</strong></p></blockquote><p>Everything else in this book will build on this foundation.</p><hr><h2 id="_1-10-what-comes-next" tabindex="-1">1.10 What Comes Next <a class="header-anchor" href="#_1-10-what-comes-next" aria-hidden="true">#</a></h2><p>Now that you understand what Machine Learning is, the next step is to understand:</p><ul><li>What different types of learning exist</li><li>How they are used in real systems</li></ul><p>In the next chapter, we will explore:</p><blockquote><p><strong>Types of Machine Learning: Supervised, Unsupervised, and Reinforcement Learning</strong></p></blockquote><hr><h2 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-hidden="true">#</a></h2><ul><li>Machine Learning replaces rule-based programming with pattern learning</li><li>It learns from data instead of explicit instructions</li><li>Every ML system has: Data \u2192 Features \u2192 Model \u2192 Prediction</li><li>It works in two phases: Training and Inference</li><li>ML is powerful when problems are too complex for manual rules</li></ul><hr><p>Take your time with this chapter. Clarity here will make everything ahead much easier.</p><hr>',102),l=[r];function s(o,h,d,c,p,m){return a(),i("div",null,l)}const f=e(t,[["render",s]]);export{g as __pageData,f as default};
